import React from 'react';
import { useHistory } from 'react-router-dom'; // Cambia useNavigate por useHistory

const Events = () => {
    const history = useHistory();
    const [table, setTable] = React.useState('PlayerStats');
    const [rows, setRows] = React.useState([]);
    const [columns, setColumns] = React.useState([]);
    const [loading, setLoading] = React.useState(true);
    const [error, setError] = React.useState('');

    React.useEffect(() => {
        let isActive = true;
        const loadStats = async () => {
            setLoading(true);
            setError('');
            try {
                const response = await fetch(`/api/stats?table=${encodeURIComponent(table)}&limit=50`);
                if (!response.ok) {
                    throw new Error('Stats request failed');
                }
                const data = await response.json();
                const nextRows = Array.isArray(data.rows) ? data.rows : [];
                const nextColumns = nextRows[0] ? Object.keys(nextRows[0]) : [];
                if (isActive) {
                    setRows(nextRows);
                    setColumns(nextColumns);
                }
            } catch (err) {
                if (isActive) {
                    setError('No se pudieron cargar las estadisticas.');
                    setRows([]);
                    setColumns([]);
                }
            } finally {
                if (isActive) {
                    setLoading(false);
                }
            }
        };

        loadStats();
        return () => {
            isActive = false;
        };
    }, [table]);

    return (
        <div
            style={{
                maxWidth: 1000,
                margin: '4rem auto',
                background: 'rgba(24,24,24,0.97)',
                borderRadius: 24,
                boxShadow: '0 8px 32px #000b',
                padding: '2.5rem 2rem',
                textAlign: 'center',
                fontFamily: 'Montserrat, Arial, sans-serif',
                color: '#fff',
                position: 'relative'
            }}
        >
            <h1
                style={{
                    color: 'var(--rust-orange)',
                    fontWeight: 900,
                    fontSize: '2.2rem',
                    marginBottom: '1.5rem',
                    letterSpacing: '2px',
                    textShadow: '0 2px 18px #000a'
                }}
            >
                Estadísticas del Evento
            </h1>
            <div style={{
                display: 'flex',
                justifyContent: 'center',
                gap: 12,
                marginBottom: '1.6rem',
                flexWrap: 'wrap'
            }}>
                <button
                    type="button"
                    onClick={() => setTable('PlayerStats')}
                    style={{
                        padding: '0.6rem 1.6rem',
                        borderRadius: 10,
                        border: '1px solid #e25822aa',
                        background: table === 'PlayerStats' ? '#e25822' : '#23201a',
                        color: '#fff',
                        fontWeight: 700,
                        cursor: 'pointer'
                    }}
                >
                    PlayerStats
                </button>
                <button
                    type="button"
                    onClick={() => setTable('StatsStorage')}
                    style={{
                        padding: '0.6rem 1.6rem',
                        borderRadius: 10,
                        border: '1px solid #e25822aa',
                        background: table === 'StatsStorage' ? '#e25822' : '#23201a',
                        color: '#fff',
                        fontWeight: 700,
                        cursor: 'pointer'
                    }}
                >
                    StatsStorage
                </button>
            </div>

            {loading && (
                <div style={{
                    padding: '1.2rem 1rem',
                    color: '#b3cfff',
                    fontWeight: 600
                }}>
                    Cargando estadisticas...
                </div>
            )}

            {!loading && error && (
                <div style={{
                    background: 'rgba(226,88,34,0.18)',
                    borderRadius: 14,
                    padding: '1rem',
                    marginBottom: '1.2rem',
                    border: '1px solid #e25822aa'
                }}>
                    {error}
                </div>
            )}

            {!loading && !error && rows.length === 0 && (
                <div style={{
                    background: 'rgba(34,34,34,0.97)',
                    borderRadius: 14,
                    padding: '1rem',
                    marginBottom: '1.2rem'
                }}>
                    Sin registros por ahora.
                </div>
            )}

            {!loading && !error && rows.length > 0 && (
                <div style={{
                    overflowX: 'auto',
                    borderRadius: 14,
                    border: '1px solid rgba(255,255,255,0.12)'
                }}>
                    <table style={{
                        width: '100%',
                        borderCollapse: 'collapse',
                        textAlign: 'left',
                        fontSize: '0.95rem'
                    }}>
                        <thead>
                            <tr style={{ background: 'rgba(35,32,26,0.9)' }}>
                                {columns.map((col) => (
                                    <th key={col} style={{
                                        padding: '0.75rem 0.9rem',
                                        borderBottom: '1px solid rgba(255,255,255,0.1)',
                                        color: '#f5d7c1'
                                    }}>
                                        {col}
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody>
                            {rows.map((row, idx) => (
                                <tr key={idx} style={{
                                    background: idx % 2 === 0 ? 'rgba(24,24,24,0.9)' : 'rgba(30,30,30,0.9)'
                                }}>
                                    {columns.map((col) => (
                                        <td key={`${idx}-${col}`} style={{
                                            padding: '0.65rem 0.9rem',
                                            borderBottom: '1px solid rgba(255,255,255,0.06)',
                                            color: '#fff'
                                        }}>
                                            {String(row[col] ?? '')}
                                        </td>
                                    ))}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
            <button
                onClick={() => history.push('/')}
                style={{
                    marginTop: '2.2rem',
                    background: 'linear-gradient(90deg, #e25822 60%, #23201a 100%)',
                    color: '#fff',
                    fontWeight: 700,
                    fontSize: '1.08rem',
                    padding: '0.8rem 2.2rem',
                    border: 'none',
                    borderRadius: 14,
                    boxShadow: '0 2px 12px #0007',
                    cursor: 'pointer',
                    transition: 'background 0.2s, transform 0.2s',
                    letterSpacing: '1px'
                }}
                onMouseOver={e => (e.currentTarget.style.transform = 'scale(1.07)')}
                onMouseOut={e => (e.currentTarget.style.transform = 'scale(1)')}
            >
                Volver al inicio
            </button>
        </div>
    );
};

export default Events;
